import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  Send, QrCode, Users, History, Settings, Coins, LogOut, CheckCircle2, 
  AlertCircle, Smartphone, ShieldCheck, LayoutDashboard, ArrowRight, 
  UploadCloud, User, Loader2, Lock, ChevronRight, PlusCircle, CreditCard, 
  Zap, ShoppingBag, Ticket, Image as ImageIcon, Film, X, Database, 
  Activity, Search, Edit, Trash2, MoreVertical, Save, ShieldAlert, 
  TrendingUp, MessageSquare, Server, Plus, Minus, Bell, LogIn, Play, Download,
  RefreshCw, ListPlus, Paperclip, XCircle, Gift, Calendar, Crown, Star, KeyRound, Building2, Mail,
  PieChart, LineChart
} from 'lucide-react';

const API_URL = 'http://localhost:5000/api';

/* ============================================================================
   CONSTANTS & PRICING
   ============================================================================ */
const SUBSCRIPTION_PACKAGES = [
  { id: 'sub_1', name: 'Basic Plan', price: 49, credits: 2000, features: ['2,000 Credits per month', 'Basic Support', 'Valid for 30 Days'], icon: Star, popular: false },
  { id: 'sub_2', name: 'Pro Plan', price: 99, credits: 5000, features: ['5,000 Credits per month', 'Priority Support', 'Valid for 30 Days'], icon: Crown, popular: true },
  { id: 'sub_3', name: 'Ultimate Plan', price: 179, credits: 10000, features: ['10,000 Credits per month', 'Dedicated Account Manager', 'Valid for 30 Days'], icon: ShieldCheck, popular: false }
];

const TOPUP_PACKAGES = [
  { id: 'tu_1', amount: 500, price: 15, label: 'Lite Reload', icon: Ticket, bonus: null },
  { id: 'tu_2', amount: 1500, price: 40, label: 'Basic Reload', icon: Zap, bonus: '+50 Bonus' },
  { id: 'tu_3', amount: 4000, price: 90, label: 'Pro Reload', icon: Coins, bonus: '+200 Bonus', popular: true },
  { id: 'tu_4', amount: 10000, price: 180, label: 'Enterprise Reload', icon: Database, bonus: '+500 Bonus' }
];

const QRCodeImage = ({ value, size = 200 }) => {
  const qrUrl = `https://quickchart.io/qr?text=${encodeURIComponent(value)}&size=${size}&margin=1`;
  return (
    <div className="bg-white p-4 rounded-3xl shadow-xl border border-slate-100 inline-block">
      <img src={qrUrl} alt="WhatsApp QR" width={size} height={size} className="rounded-xl" />
    </div>
  );
};

/* ============================================================================
   ADMIN PORTAL (DIPERBAHARUI & DIBANGUNKAN SEPENUHNYA)
   ============================================================================ */
const AdminPortal = ({ currentUser, onLogout, token }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [allUsers, setAllUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // State untuk Notifikasi & Modal
  const [notification, setNotification] = useState({ show: false, title: '', message: '', type: 'info' });
  const [manageUserModal, setManageUserModal] = useState({ isOpen: false, user: null, newCredit: 0 });

  const showNotification = (title, message, type = 'info') => {
    setNotification({ show: true, title, message, type });
  };

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/admin/users`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setAllUsers(data);
      }
    } catch (err) { 
      showNotification("Ralat", "Gagal mengambil data pengguna dari pelayan.", "error"); 
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchUsers();
  }, [token]);

  // Statistik Dinamik
  const totalUsers = allUsers.length;
  const totalCredits = allUsers.reduce((sum, user) => sum + (user.kredit || 0), 0);
  const activeSessions = allUsers.filter(user => user.sesi_whatsapp_aktif).length;

  // Carian Pelanggan
  const filteredUsers = allUsers.filter(u => 
    u.nama_syarikat?.toLowerCase().includes(searchQuery.toLowerCase()) ||
    u.email?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleUpdateCreditSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch(`${API_URL}/admin/update-credit`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: JSON.stringify({ userId: manageUserModal.user._id, kredit: parseInt(manageUserModal.newCredit) })
      });
      if (res.ok) {
        showNotification("Berjaya", `Kredit ${manageUserModal.user.nama_syarikat} telah dikemaskini.`, "success");
        setManageUserModal({ isOpen: false, user: null, newCredit: 0 });
        fetchUsers();
      } else {
        showNotification("Ralat", "Gagal menyimpan data kredit.", "error");
      }
    } catch (err) { 
      showNotification("Ralat Rangkaian", "Pelayan tidak dapat dihubungi.", "error"); 
    }
  };

  const openManageModal = (user) => {
    setManageUserModal({ isOpen: true, user: user, newCredit: user.kredit });
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 flex w-full relative">
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>

      {/* GLOBAL NOTIFICATION MODAL */}
      {notification.show && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white p-8 rounded-[2rem] shadow-2xl max-w-sm w-full text-center border border-slate-100">
            <div className="flex justify-center mb-5">
              {notification.type === 'warning' ? <AlertCircle size={56} className="text-amber-500" /> :
               notification.type === 'error' ? <XCircle size={56} className="text-red-500" /> :
               <CheckCircle2 size={56} className="text-emerald-500" />}
            </div>
            <h3 className="text-xl font-black text-slate-800 mb-2">{notification.title}</h3>
            <p className="text-slate-500 font-medium mb-8 text-sm">{notification.message}</p>
            <button onClick={() => setNotification({ ...notification, show: false })} className="w-full py-3.5 bg-slate-900 text-white rounded-2xl font-black hover:bg-slate-800 transition-colors">Tutup</button>
          </div>
        </div>
      )}

      {/* MANAGE USER MODAL */}
      {manageUserModal.isOpen && (
        <div className="fixed inset-0 z-[90] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-[2.5rem] shadow-2xl max-w-md w-full border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-6 flex justify-between items-center text-white">
               <div className="flex items-center gap-3">
                 <div className="bg-emerald-500 p-2 rounded-xl text-white"><Settings size={20}/></div>
                 <h3 className="font-black text-lg">Kemaskini Akaun</h3>
               </div>
               <button onClick={() => setManageUserModal({ isOpen: false, user: null, newCredit: 0 })} className="text-slate-400 hover:text-white"><X size={24}/></button>
            </div>

            <form onSubmit={handleUpdateCreditSubmit} className="p-8 space-y-6">
                <div className="space-y-1">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nama Syarikat / Pelanggan</p>
                  <p className="font-bold text-lg text-slate-800">{manageUserModal.user.nama_syarikat}</p>
                  <p className="text-xs text-slate-500 font-medium">{manageUserModal.user.email}</p>
                </div>

                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex justify-between items-center">
                   <div>
                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Baki Kredit Semasa</p>
                     <p className="font-black text-2xl text-slate-900">{manageUserModal.user.kredit}</p>
                   </div>
                   <Coins size={32} className="text-emerald-500 opacity-50" />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tetapkan Baki Kredit Baru</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      required 
                      min="0"
                      value={manageUserModal.newCredit} 
                      onChange={(e) => setManageUserModal({...manageUserModal, newCredit: e.target.value})}
                      className="w-full p-4 pl-12 bg-white border-2 border-slate-200 rounded-2xl font-black text-xl outline-none focus:border-emerald-500 transition-colors text-emerald-600" 
                    />
                    <Edit className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                  </div>
                  <p className="text-[10px] text-slate-500 font-bold mt-1">*Ubah jumlah di atas untuk menambah atau memotong kredit pelanggan.</p>
                </div>

                <button type="submit" className="w-full py-4 bg-emerald-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-100 flex items-center justify-center gap-2 mt-4">
                  <Save size={16} /> Simpan Perubahan
                </button>
            </form>
          </div>
        </div>
      )}

      {/* SIDEBAR */}
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col h-screen fixed left-0 top-0 hidden lg:flex">
        <div className="h-24 flex items-center px-6 border-b border-slate-800 bg-slate-950 flex-shrink-0">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-500 p-3 rounded-2xl text-white shadow-lg shadow-emerald-500/20">
              <ShieldAlert size={24} fill="currentColor" />
            </div>
            <div>
              <h1 className="text-white font-black text-xl leading-tight tracking-tight">ADMIN</h1>
              <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest">AR Connect Portal</p>
            </div>
          </div>
        </div>

        <nav className="flex-1 overflow-y-auto hide-scrollbar p-4 space-y-2 mt-4">
          <p className="px-4 text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4">Navigasi Utama</p>
          {[
            { id: 'dashboard', icon: PieChart, label: 'Papan Pemuka' },
            { id: 'users', icon: Users, label: 'Pengurusan Pengguna' },
            { id: 'settings', icon: Settings, label: 'Tetapan Sistem' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-4 px-4 py-3.5 rounded-2xl font-bold transition-all text-sm ${
                activeTab === item.id 
                  ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' 
                  : 'hover:bg-slate-800 hover:text-white text-slate-400'
              }`}
            >
              <item.icon size={20} />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-6 border-t border-slate-800 flex-shrink-0 bg-slate-950/50">
          <div className="flex items-center gap-3 mb-4 p-3 bg-slate-800/50 rounded-2xl border border-slate-800">
             <div className="w-10 h-10 bg-slate-800 rounded-xl flex items-center justify-center text-slate-400"><ShieldCheck size={20}/></div>
             <div>
               <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Log Masuk Sebagai</p>
               <p className="text-xs font-bold text-white truncate">Super Admin</p>
             </div>
          </div>
          <button onClick={onLogout} className="w-full flex items-center justify-center gap-2 px-4 py-3.5 text-xs font-black text-red-400 hover:bg-red-500 hover:text-white rounded-2xl transition-all border border-red-500/20 hover:border-red-500 uppercase tracking-widest">
            <LogOut size={16} /> Log Keluar
          </button>
        </div>
      </aside>

      {/* MAIN CONTENT AREA */}
      <main className="flex-1 lg:ml-64 flex flex-col h-screen overflow-hidden bg-slate-50/50">
        <header className="h-24 bg-white border-b border-slate-200 flex items-center justify-between px-6 lg:px-10 sticky top-0 z-10 flex-shrink-0">
          <div>
            <h2 className="text-2xl font-black text-slate-900 tracking-tight">
              {activeTab === 'dashboard' ? 'Papan Pemuka' : activeTab === 'users' ? 'Pengurusan Pengguna' : 'Tetapan Sistem'}
            </h2>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Sistem Pengurusan Pusat</p>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-2 px-4 py-2 bg-emerald-50 text-emerald-600 rounded-full border border-emerald-100 text-xs font-black uppercase tracking-widest">
               <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div> Sistem Aktif
            </div>

            <div className="flex lg:hidden gap-2">
              <button onClick={() => setActiveTab('dashboard')} className={`p-2.5 rounded-xl ${activeTab === 'dashboard' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}><PieChart size={20}/></button>
